import{_ as r,o as a,c as t,ak as o}from"./chunks/framework.Dx0ZwfXr.js";const m=JSON.parse('{"title":"RdpClient9","description":"","frontmatter":{},"headers":[],"relativePath":"api/reference/royalapps-community-rdp-winforms-controls-clients-rdpclient9.md","filePath":"api/reference/royalapps-community-rdp-winforms-controls-clients-rdpclient9.md"}'),i={name:"api/reference/royalapps-community-rdp-winforms-controls-clients-rdpclient9.md"};function n(s,e,c,l,d,h){return a(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="rdpclient9" tabindex="-1"><code>RdpClient9</code> <a class="header-anchor" href="#rdpclient9" aria-label="Permalink to “RdpClient9”">​</a></h1><p>Provides safe, logged access to the properties, methods, and events exposed by the underlying RDP ActiveX control.</p><h2 id="type" tabindex="-1">Type <a class="header-anchor" href="#type" aria-label="Permalink to “Type”">​</a></h2><div class="language-csharp"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">RoyalApps.Community.Rdp.WinForms.Controls.Clients.RdpClient9</span></span></code></pre></div><h2 id="related-types" tabindex="-1">Related Types <a class="header-anchor" href="#related-types" aria-label="Permalink to “Related Types”">​</a></h2><ul><li><a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-controls-clients-irdpclient">IRdpClient</a></li></ul><h2 id="properties" tabindex="-1">Properties <a class="header-anchor" href="#properties" aria-label="Permalink to “Properties”">​</a></h2><h3 id="acceleratorpassthrough-bool-↗" tabindex="-1"><code>AcceleratorPassthrough</code> (<code>bool</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclientadvancedsettings-acceleratorpassthrough" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#acceleratorpassthrough-bool-↗" aria-label="Permalink to “AcceleratorPassthrough (bool) ↗”">​</a></h3><p>Specifies whether keyboard accelerators should be passed to the server.</p><h3 id="allowbackgroundinput-bool-↗" tabindex="-1"><code>AllowBackgroundInput</code> (<code>bool</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imstscadvancedsettings-allowbackgroundinput" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#allowbackgroundinput-bool-↗" aria-label="Permalink to “AllowBackgroundInput (bool) ↗”">​</a></h3><p>Specifies whether the client can accept input while it does not have focus.</p><h3 id="audiocaptureredirectionmode-bool-↗" tabindex="-1"><code>AudioCaptureRedirectionMode</code> (<code>bool</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclientadvancedsettings7-audiocaptureredirectionmode" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#audiocaptureredirectionmode-bool-↗" aria-label="Permalink to “AudioCaptureRedirectionMode (bool) ↗”">​</a></h3><p>Specifies whether the default audio input device is redirected from the client to the remote session.</p><h3 id="audioqualitymode-audioqualitymode-↗" tabindex="-1"><code>AudioQualityMode</code> (<a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-configuration-performance-audioqualitymode">AudioQualityMode</a>) <a class="api-member-external-link" href="https://learn.microsoft.com/en-us/windows/win32/termserv/imsrdpclientadvancedsettings7-audioqualitymode" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#audioqualitymode-audioqualitymode-↗" aria-label="Permalink to “AudioQualityMode (AudioQualityMode) ↗”">​</a></h3><p>Specifies the audio quality mode.</p><h3 id="audioredirectionmode-audioredirectionmode-↗" tabindex="-1"><code>AudioRedirectionMode</code> (<a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-configuration-performance-audioredirectionmode">AudioRedirectionMode</a>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclientsecuredsettings-autoredirectionmode" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#audioredirectionmode-audioredirectionmode-↗" aria-label="Permalink to “AudioRedirectionMode (AudioRedirectionMode) ↗”">​</a></h3><p>Specifies how audio output is handled for the remote session.</p><h3 id="authenticationlevel-authenticationlevel" tabindex="-1"><code>AuthenticationLevel</code> (<a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-configuration-connection-authenticationlevel">AuthenticationLevel</a>) <a class="header-anchor" href="#authenticationlevel-authenticationlevel" aria-label="Permalink to “AuthenticationLevel (AuthenticationLevel)”">​</a></h3><p>Specifies the server authentication level used for the connection.</p><h3 id="authenticationserviceclass-string-↗" tabindex="-1"><code>AuthenticationServiceClass</code> (<code>string</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclientadvancedsettings6-authenticationserviceclass" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#authenticationserviceclass-string-↗" aria-label="Permalink to “AuthenticationServiceClass (string) ↗”">​</a></h3><p>Specifies the service principal name (SPN) to use for authentication to the server.</p><h3 id="axname-string" tabindex="-1"><code>AxName</code> (<code>string</code>) <a class="header-anchor" href="#axname-string" aria-label="Permalink to “AxName (string)”">​</a></h3><p>Gets or sets the name of the underlying RDP ActiveX implementation, for example <code>mstsc</code> or <code>msrdc</code>.</p><h3 id="bandwidthdetection-bool-↗" tabindex="-1"><code>BandwidthDetection</code> (<code>bool</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclientadvancedsettings8-bandwidthdetection" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#bandwidthdetection-bool-↗" aria-label="Permalink to “BandwidthDetection (bool) ↗”">​</a></h3><p>Specifies whether bandwidth changes are detected automatically.</p><h3 id="bitmapcaching-bool-↗" tabindex="-1"><code>BitmapCaching</code> (<code>bool</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclientadvancedsettings-bitmappersistence" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#bitmapcaching-bool-↗" aria-label="Permalink to “BitmapCaching (bool) ↗”">​</a></h3><p>Specifies whether bitmap caching is enabled. Persistent caching can improve performance but requires additional disk space.</p><h3 id="clientprotocolspec-clientspec" tabindex="-1"><code>ClientProtocolSpec</code> (<code>ClientSpec</code>) <a class="header-anchor" href="#clientprotocolspec-clientspec" aria-label="Permalink to “ClientProtocolSpec (ClientSpec)”">​</a></h3><p>Specifies the RDP protocol profile used between the client and the server.</p><h3 id="compression-bool-↗" tabindex="-1"><code>Compression</code> (<code>bool</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imstscadvancedsettings-compress" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#compression-bool-↗" aria-label="Permalink to “Compression (bool) ↗”">​</a></h3><p>Specifies whether compression is enabled.</p><h3 id="connectionstate-connectionstate" tabindex="-1"><code>ConnectionState</code> (<a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-controls-clients-connectionstate">ConnectionState</a>) <a class="header-anchor" href="#connectionstate-connectionstate" aria-label="Permalink to “ConnectionState (ConnectionState)”">​</a></h3><p>Gets the current connection state of the control.</p><h3 id="connecttoadministerserver-bool-↗" tabindex="-1"><code>ConnectToAdministerServer</code> (<code>bool</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclientadvancedsettings6-connecttoadministerserver" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#connecttoadministerserver-bool-↗" aria-label="Permalink to “ConnectToAdministerServer (bool) ↗”">​</a></h3><p>Specifies whether the ActiveX control should attempt to connect to the server for administrative purposes.</p><h3 id="containerhandledfullscreen-int-↗" tabindex="-1"><code>ContainerHandledFullScreen</code> (<code>int</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imstscadvancedsettings-containerhandledfullscreen" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#containerhandledfullscreen-int-↗" aria-label="Permalink to “ContainerHandledFullScreen (int) ↗”">​</a></h3><p>Specifies whether the container-handled full-screen mode is enabled.</p><h3 id="desktopscalefactor-uint-↗" tabindex="-1"><code>DesktopScaleFactor</code> (<code>uint</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/openspecs/windows_protocols/ms-rdpbcgr/8fb3a83c-f3e2-4a81-8824-8173af03b6bc" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#desktopscalefactor-uint-↗" aria-label="Permalink to “DesktopScaleFactor (uint) ↗”">​</a></h3><p>Gets or sets the desktop scale factor for the monitor.</p><h3 id="devicescalefactor-uint-↗" tabindex="-1"><code>DeviceScaleFactor</code> (<code>uint</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/openspecs/windows_protocols/ms-rdpbcgr/8fb3a83c-f3e2-4a81-8824-8173af03b6bc" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#devicescalefactor-uint-↗" aria-label="Permalink to “DeviceScaleFactor (uint) ↗”">​</a></h3><p>Gets or sets the device scale factor for the monitor.</p><h3 id="disableclickdetection-bool" tabindex="-1"><code>DisableClickDetection</code> (<code>bool</code>) <a class="header-anchor" href="#disableclickdetection-bool" aria-label="Permalink to “DisableClickDetection (bool)”">​</a></h3><p>When <code>true</code>, a click in the remote session does not focus the control and does not trigger the <a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-controls-clients-irdpclient">IRdpClient.OnClientAreaClicked</a> event.</p><h3 id="disablecredentialsdelegation-bool-↗" tabindex="-1"><code>DisableCredentialsDelegation</code> (<code>bool</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpextendedsettings-property" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#disablecredentialsdelegation-bool-↗" aria-label="Permalink to “DisableCredentialsDelegation (bool) ↗”">​</a></h3><p>When <code>true</code>, reusable credentials are not delegated to the remote server.</p><h3 id="disableudptransport-bool" tabindex="-1"><code>DisableUdpTransport</code> (<code>bool</code>) <a class="header-anchor" href="#disableudptransport-bool" aria-label="Permalink to “DisableUdpTransport (bool)”">​</a></h3><p>Disables RDP UDP transport and forces TCP transport. This is commonly useful when connecting through UDP-based VPN links.</p><h3 id="displayconnectionbar-bool-↗" tabindex="-1"><code>DisplayConnectionBar</code> (<code>bool</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclientadvancedsettings-displayconnectionbar" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#displayconnectionbar-bool-↗" aria-label="Permalink to “DisplayConnectionBar (bool) ↗”">​</a></h3><p>Specifies whether to use the connection bar. The default value is true, which enables the property.</p><h3 id="enableautoreconnect-bool-↗" tabindex="-1"><code>EnableAutoReconnect</code> (<code>bool</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclientadvancedsettings2-enableautoreconnect" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#enableautoreconnect-bool-↗" aria-label="Permalink to “EnableAutoReconnect (bool) ↗”">​</a></h3><p>Specifies whether the client control should reconnect automatically after a network interruption.</p><h3 id="enablehardwaremode-bool" tabindex="-1"><code>EnableHardwareMode</code> (<code>bool</code>) <a class="header-anchor" href="#enablehardwaremode-bool" aria-label="Permalink to “EnableHardwareMode (bool)”">​</a></h3><p>When <code>true</code>, hardware-assisted graphics decoding is attempted.</p><h3 id="enablemousejiggler-bool" tabindex="-1"><code>EnableMouseJiggler</code> (<code>bool</code>) <a class="header-anchor" href="#enablemousejiggler-bool" aria-label="Permalink to “EnableMouseJiggler (bool)”">​</a></h3><p>When <code>true</code>, the session is kept alive through periodic, non-intrusive input simulation to help avoid idle-time disconnects.</p><h3 id="enablerdsaadauth-bool" tabindex="-1"><code>EnableRdsAadAuth</code> (<code>bool</code>) <a class="header-anchor" href="#enablerdsaadauth-bool" aria-label="Permalink to “EnableRdsAadAuth (bool)”">​</a></h3><p>Specifies whether Microsoft Entra ID is used to authenticate to the remote PC.</p><h3 id="enablewindowskey-bool-↗" tabindex="-1"><code>EnableWindowsKey</code> (<code>bool</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclientadvancedsettings-enablewindowskey" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#enablewindowskey-bool-↗" aria-label="Permalink to “EnableWindowsKey (bool) ↗”">​</a></h3><p>Specifies whether the Windows key can be used in the remote session.</p><h3 id="gatewaycredsharing-bool-↗" tabindex="-1"><code>GatewayCredSharing</code> (<code>bool</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclienttransportsettings2-gatewaycredsharing" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#gatewaycredsharing-bool-↗" aria-label="Permalink to “GatewayCredSharing (bool) ↗”">​</a></h3><p>Specifies whether the same credentials should be reused for both the RD Gateway server and the target session host.</p><h3 id="gatewaycredssource-gatewaycredentialsource-↗" tabindex="-1"><code>GatewayCredsSource</code> (<a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-configuration-connection-gatewaycredentialsource">GatewayCredentialSource</a>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclienttransportsettings-gatewaycredssource" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#gatewaycredssource-gatewaycredentialsource-↗" aria-label="Permalink to “GatewayCredsSource (GatewayCredentialSource) ↗”">​</a></h3><p>Specifies the Remote Desktop Gateway (RD Gateway) authentication method.</p><h3 id="gatewaydomain-string-↗" tabindex="-1"><code>GatewayDomain</code> (<code>string</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclienttransportsettings2-gatewaydomain" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#gatewaydomain-string-↗" aria-label="Permalink to “GatewayDomain (string) ↗”">​</a></h3><p>Specifies the domain name used to authenticate to the Remote Desktop Gateway (RD Gateway) server.</p><h3 id="gatewayhostname-string-↗" tabindex="-1"><code>GatewayHostname</code> (<code>string</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclienttransportsettings-gatewayhostname" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#gatewayhostname-string-↗" aria-label="Permalink to “GatewayHostname (string) ↗”">​</a></h3><p>Specifies the host name of the Remote Desktop Gateway (RD Gateway) server.</p><h3 id="gatewaypassword-string-↗" tabindex="-1"><code>GatewayPassword</code> (<code>string</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclienttransportsettings2-gatewaypassword" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#gatewaypassword-string-↗" aria-label="Permalink to “GatewayPassword (string) ↗”">​</a></h3><p>Specifies the password used to authenticate to the Remote Desktop Gateway (RD Gateway) server.</p><h3 id="gatewayprofileusagemethod-gatewayprofileusagemethod-↗" tabindex="-1"><code>GatewayProfileUsageMethod</code> (<a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-configuration-connection-gatewayprofileusagemethod">GatewayProfileUsageMethod</a>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclienttransportsettings-gatewayprofileusagemethod" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#gatewayprofileusagemethod-gatewayprofileusagemethod-↗" aria-label="Permalink to “GatewayProfileUsageMethod (GatewayProfileUsageMethod) ↗”">​</a></h3><p>Specifies whether to use default Remote Desktop Gateway (RD Gateway) settings.</p><h3 id="gatewayusagemethod-gatewayusagemethod-↗" tabindex="-1"><code>GatewayUsageMethod</code> (<a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-configuration-connection-gatewayusagemethod">GatewayUsageMethod</a>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclienttransportsettings-gatewayusagemethod" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#gatewayusagemethod-gatewayusagemethod-↗" aria-label="Permalink to “GatewayUsageMethod (GatewayUsageMethod) ↗”">​</a></h3><p>Specifies when to use a Remote Desktop Gateway (RD Gateway) server.</p><h3 id="gatewayusername-string-↗" tabindex="-1"><code>GatewayUsername</code> (<code>string</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclienttransportsettings2-gatewayusername" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#gatewayusername-string-↗" aria-label="Permalink to “GatewayUsername (string) ↗”">​</a></h3><p>Specifies the user name used to authenticate to the Remote Desktop Gateway (RD Gateway) server.</p><h3 id="gatewayuserselectedcredssource-gatewaycredentialsource-↗" tabindex="-1"><code>GatewayUserSelectedCredsSource</code> (<a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-configuration-connection-gatewaycredentialsource">GatewayCredentialSource</a>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclienttransportsettings-gatewayuserselectedcredssource" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#gatewayuserselectedcredssource-gatewaycredentialsource-↗" aria-label="Permalink to “GatewayUserSelectedCredsSource (GatewayCredentialSource) ↗”">​</a></h3><p>Specifies the user-selected Remote Desktop Gateway (RD Gateway) credential source.</p><h3 id="grabfocusonconnect-bool-↗" tabindex="-1"><code>GrabFocusOnConnect</code> (<code>bool</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclientadvancedsettings-grabfocusonconnect" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#grabfocusonconnect-bool-↗" aria-label="Permalink to “GrabFocusOnConnect (bool) ↗”">​</a></h3><p>Specifies whether the client control should have focus while connecting. The control does not attempt to grab focus from a window running in a different process.</p><h3 id="keepaliveinterval-int-↗" tabindex="-1"><code>KeepAliveInterval</code> (<code>int</code>) <a class="api-member-external-link" href="https://learn.microsoft.com/en-us/windows/win32/termserv/imsrdpclientadvancedsettings-keepaliveinterval" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#keepaliveinterval-int-↗" aria-label="Permalink to “KeepAliveInterval (int) ↗”">​</a></h3><p>Gets or sets the interval, in milliseconds, between keep-alive packets.</p><h3 id="keyboardhookmode-int-↗" tabindex="-1"><code>KeyboardHookMode</code> (<code>int</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclientsecuredsettings-keyboardhookmode" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#keyboardhookmode-int-↗" aria-label="Permalink to “KeyboardHookMode (int) ↗”">​</a></h3><p>Specifies how Windows keyboard shortcuts, for example ALT+TAB, are redirected to the remote session.</p><h3 id="keyboardlayoutstr-string-↗" tabindex="-1"><code>KeyBoardLayoutStr</code> (<code>string</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imstscadvancedsettings-keyboardlayoutstr" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#keyboardlayoutstr-string-↗" aria-label="Permalink to “KeyBoardLayoutStr (string) ↗”">​</a></h3><p>Specifies the input locale identifier, formerly called the keyboard layout, used for the connection.</p><h3 id="loadbalanceinfo-string-↗" tabindex="-1"><code>LoadBalanceInfo</code> (<code>string</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclientadvancedsettings-loadbalanceinfo" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#loadbalanceinfo-string-↗" aria-label="Permalink to “LoadBalanceInfo (string) ↗”">​</a></h3><p>Specifies the load-balancing cookie written into the initial X.224 connection request.</p><h3 id="logger-ilogger" tabindex="-1"><code>Logger</code> (<code>ILogger</code>) <a class="header-anchor" href="#logger-ilogger" aria-label="Permalink to “Logger (ILogger)”">​</a></h3><p>Gets or sets the logger used by the RDP client wrapper.</p><h3 id="maximizeshell-bool-↗" tabindex="-1"><code>MaximizeShell</code> (<code>bool</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclientadvancedsettings-maximizeshell" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#maximizeshell-bool-↗" aria-label="Permalink to “MaximizeShell (bool) ↗”">​</a></h3><p>Specifies whether programs launched with <a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-controls-clients-irdpclient">IRdpClient.StartProgram</a> should be maximized.</p><h3 id="maxreconnectattempts-int-↗" tabindex="-1"><code>MaxReconnectAttempts</code> (<code>int</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclientadvancedsettings2-maxreconnectattempts" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#maxreconnectattempts-int-↗" aria-label="Permalink to “MaxReconnectAttempts (int) ↗”">​</a></h3><p>Specifies the number of times to try to reconnect during automatic reconnection. Valid values are 0 to 200.</p><h3 id="mousejigglerinterval-int" tabindex="-1"><code>MouseJigglerInterval</code> (<code>int</code>) <a class="header-anchor" href="#mousejigglerinterval-int" aria-label="Permalink to “MouseJigglerInterval (int)”">​</a></h3><p>Gets or sets the interval, in seconds, between mouse-jiggler keep-alive actions.</p><h3 id="mousejigglermethod-keepalivemethod" tabindex="-1"><code>MouseJigglerMethod</code> (<a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-configuration-input-keepalivemethod">KeepAliveMethod</a>) <a class="header-anchor" href="#mousejigglermethod-keepalivemethod" aria-label="Permalink to “MouseJigglerMethod (KeepAliveMethod)”">​</a></h3><p>Gets or sets the mouse-jiggler method. <code>MouseMove</code> simulates mouse input and <code>KeyboardInput</code> simulates an <code>F15</code> key press.</p><h3 id="networkconnectiontype-uint-↗" tabindex="-1"><code>NetworkConnectionType</code> (<code>uint</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclientadvancedsettings7-networkconnectiontype" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#networkconnectiontype-uint-↗" aria-label="Permalink to “NetworkConnectionType (uint) ↗”">​</a></h3><p>Gets or sets the network connection type reported to the server.</p><h3 id="networklevelauthentication-bool-↗" tabindex="-1"><code>NetworkLevelAuthentication</code> (<code>bool</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclientadvancedsettings6-enablecredsspsupport" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#networklevelauthentication-bool-↗" aria-label="Permalink to “NetworkLevelAuthentication (bool) ↗”">​</a></h3><p>Specifies whether the Credential Security Support Provider (CredSSP) and network-level authentication are enabled for this connection. Availability depends on the underlying ActiveX client version.</p><h3 id="password-string-↗" tabindex="-1"><code>Password</code> (<code>string</code>?) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imstscnonscriptable-cleartextpassword" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#password-string-↗" aria-label="Permalink to “Password (string?) ↗”">​</a></h3><p>Sets the Remote Desktop ActiveX control password in plaintext form. After it is set, it cannot be retrieved in plaintext form.</p><h3 id="passwordcontainssmartcardpin-bool" tabindex="-1"><code>PasswordContainsSmartCardPin</code> (<code>bool</code>) <a class="header-anchor" href="#passwordcontainssmartcardpin-bool" aria-label="Permalink to “PasswordContainsSmartCardPin (bool)”">​</a></h3><p>Specifies whether the password contains a smart card PIN.</p><h3 id="pcb-string-↗" tabindex="-1"><code>PCB</code> (<code>string</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclientadvancedsettings6-pcb" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#pcb-string-↗" aria-label="Permalink to “PCB (string) ↗”">​</a></h3><p>Specifies the pre-connection BLOB (PCB) value sent to the server before connecting.</p><h3 id="performanceflags-int-↗" tabindex="-1"><code>PerformanceFlags</code> (<code>int</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclientadvancedsettings-performanceflags" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#performanceflags-int-↗" aria-label="Permalink to “PerformanceFlags (int) ↗”">​</a></h3><p>Specifies a set of features that can be set at the server to improve performance.</p><h3 id="pinconnectionbar-bool-↗" tabindex="-1"><code>PinConnectionBar</code> (<code>bool</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclientadvancedsettings-pinconnectionbar" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#pinconnectionbar-bool-↗" aria-label="Permalink to “PinConnectionBar (bool) ↗”">​</a></h3><p>Specifies whether the UI connection bar is pinned in the lowered state.</p><h3 id="plugindlls-string-↗" tabindex="-1"><code>PluginDlls</code> (<code>string</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imstscadvancedsettings-plugindlls" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#plugindlls-string-↗" aria-label="Permalink to “PluginDlls (string) ↗”">​</a></h3><p>Specifies the comma-separated names of virtual channel plug-in DLLs to load.</p><h3 id="port-int-↗" tabindex="-1"><code>Port</code> (<code>int</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclientadvancedsettings-rdpport" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#port-int-↗" aria-label="Permalink to “Port (int) ↗”">​</a></h3><p>Specifies the connection port. The default value is 3389.</p><h3 id="publicmode-bool-↗" tabindex="-1"><code>PublicMode</code> (<code>bool</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclientadvancedsettings5-publicmode" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#publicmode-bool-↗" aria-label="Permalink to “PublicMode (bool) ↗”">​</a></h3><p>Specifies whether public mode is enabled. Public mode prevents the client from caching user data locally.</p><h3 id="rdpexdll-string" tabindex="-1"><code>RdpExDll</code> (<code>string</code>) <a class="header-anchor" href="#rdpexdll-string" aria-label="Permalink to “RdpExDll (string)”">​</a></h3><p>Gets or sets the path to the MsRdpEx hook library used by the underlying ActiveX client.</p><h3 id="redirectcameras-bool-↗" tabindex="-1"><code>RedirectCameras</code> (<code>bool</code>) <a class="api-member-external-link" href="https://learn.microsoft.com/en-us/windows/win32/termserv/imsrdpclientnonscriptable7-cameraredirconfigcollection" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#redirectcameras-bool-↗" aria-label="Permalink to “RedirectCameras (bool) ↗”">​</a></h3><p>Specifies whether camera redirection is allowed.</p><h3 id="redirectclipboard-bool-↗" tabindex="-1"><code>RedirectClipboard</code> (<code>bool</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclientadvancedsettings5-redirectclipboard" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#redirectclipboard-bool-↗" aria-label="Permalink to “RedirectClipboard (bool) ↗”">​</a></h3><p>Specifies whether clipboard redirection is enabled.</p><h3 id="redirectdevices-bool-↗" tabindex="-1"><code>RedirectDevices</code> (<code>bool</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclientadvancedsettings5-redirectdevices" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#redirectdevices-bool-↗" aria-label="Permalink to “RedirectDevices (bool) ↗”">​</a></h3><p>Specifies whether general device redirection is enabled.</p><h3 id="redirectdirectx-bool-↗" tabindex="-1"><code>RedirectDirectX</code> (<code>bool</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclientadvancedsettings7-redirectdirectx" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#redirectdirectx-bool-↗" aria-label="Permalink to “RedirectDirectX (bool) ↗”">​</a></h3><p>Specifies whether DirectX redirection is enabled.</p><h3 id="redirectdrives-bool-↗" tabindex="-1"><code>RedirectDrives</code> (<code>bool</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclientadvancedsettings-redirectdrives" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#redirectdrives-bool-↗" aria-label="Permalink to “RedirectDrives (bool) ↗”">​</a></h3><p>Specifies whether drive redirection is allowed.</p><h3 id="redirectedauthentication-bool" tabindex="-1"><code>RedirectedAuthentication</code> (<code>bool</code>) <a class="header-anchor" href="#redirectedauthentication-bool" aria-label="Permalink to “RedirectedAuthentication (bool)”">​</a></h3><p>When <code>true</code>, authentication is redirected back to the local device. This property and <a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-controls-clients-irdpclient">IRdpClient.DisableCredentialsDelegation</a> must both be enabled for <a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-controls-clients-irdpclient">IRdpClient.RemoteCredentialGuard</a>.</p><h3 id="redirectlocation-bool-↗" tabindex="-1"><code>RedirectLocation</code> (<code>bool</code>) <a class="api-member-external-link" href="https://learn.microsoft.com/en-us/windows/win32/termserv/imsrdpextendedsettings-property#property-value" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#redirectlocation-bool-↗" aria-label="Permalink to “RedirectLocation (bool) ↗”">​</a></h3><p>Specifies whether location redirection is allowed.</p><h3 id="redirectports-bool-↗" tabindex="-1"><code>RedirectPorts</code> (<code>bool</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclientadvancedsettings-redirectports" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#redirectports-bool-↗" aria-label="Permalink to “RedirectPorts (bool) ↗”">​</a></h3><p>Specifies whether local port redirection, for example COM and LPT, is allowed.</p><h3 id="redirectposdevices-bool-↗" tabindex="-1"><code>RedirectPOSDevices</code> (<code>bool</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclientadvancedsettings5-redirectposdevices" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#redirectposdevices-bool-↗" aria-label="Permalink to “RedirectPOSDevices (bool) ↗”">​</a></h3><p>Specifies whether Point of Service device redirection is enabled.</p><h3 id="redirectprinters-bool-↗" tabindex="-1"><code>RedirectPrinters</code> (<code>bool</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclientadvancedsettings-redirectprinters" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#redirectprinters-bool-↗" aria-label="Permalink to “RedirectPrinters (bool) ↗”">​</a></h3><p>Specifies whether printer redirection is allowed.</p><h3 id="redirectsmartcards-bool-↗" tabindex="-1"><code>RedirectSmartCards</code> (<code>bool</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclientadvancedsettings-redirectsmartcards" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#redirectsmartcards-bool-↗" aria-label="Permalink to “RedirectSmartCards (bool) ↗”">​</a></h3><p>Specifies whether smart card redirection is allowed.</p><h3 id="relativemousemode-bool-↗" tabindex="-1"><code>RelativeMouseMode</code> (<code>bool</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclientadvancedsettings6-relativemousemode" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#relativemousemode-bool-↗" aria-label="Permalink to “RelativeMouseMode (bool) ↗”">​</a></h3><p>Specifies whether the mouse should use relative mode instead of absolute mode.</p><h3 id="restrictedlogon-bool" tabindex="-1"><code>RestrictedLogon</code> (<code>bool</code>) <a class="header-anchor" href="#restrictedlogon-bool" aria-label="Permalink to “RestrictedLogon (bool)”">​</a></h3><p>When <code>true</code>, restricted logon mode is enabled. This is one of the building blocks used by restricted administration scenarios together with <a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-controls-clients-irdpclient">IRdpClient.DisableCredentialsDelegation</a>.</p><h3 id="showconnectioninformation-bool" tabindex="-1"><code>ShowConnectionInformation</code> (<code>bool</code>) <a class="header-anchor" href="#showconnectioninformation-bool" aria-label="Permalink to “ShowConnectionInformation (bool)”">​</a></h3><p>Shows the Connection Information dialog.</p><h3 id="smartsizing-bool-↗" tabindex="-1"><code>SmartSizing</code> (<code>bool</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclientadvancedsettings-smartsizing" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#smartsizing-bool-↗" aria-label="Permalink to “SmartSizing (bool) ↗”">​</a></h3><p>Specifies whether the display should be scaled to fit the client area of the control. This property can be changed while connected.</p><h3 id="startprogram-string-↗" tabindex="-1"><code>StartProgram</code> (<code>string</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imstscsecuredsettings-startprogram" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#startprogram-string-↗" aria-label="Permalink to “StartProgram (string) ↗”">​</a></h3><p>Specifies the program to be started on the remote server upon connection.</p><h3 id="useredirectionservername-bool-↗" tabindex="-1"><code>UseRedirectionServerName</code> (<code>bool</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdppreferredredirectioninfo-useredirectionservername" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#useredirectionservername-bool-↗" aria-label="Permalink to “UseRedirectionServerName (bool) ↗”">​</a></h3><p>Specifies whether the redirected server name should be used when the broker redirects the connection.</p><h3 id="videoplaybackmode-videoplaybackmode-↗" tabindex="-1"><code>VideoPlaybackMode</code> (<a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-configuration-performance-videoplaybackmode">VideoPlaybackMode</a>) <a class="api-member-external-link" href="https://learn.microsoft.com/en-us/windows/win32/termserv/imsrdpclientadvancedsettings7-videoplaybackmode" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#videoplaybackmode-videoplaybackmode-↗" aria-label="Permalink to “VideoPlaybackMode (VideoPlaybackMode) ↗”">​</a></h3><p>Specifies whether video decoding and rendering are redirected to the client.</p><h3 id="workdir-string-↗" tabindex="-1"><code>WorkDir</code> (<code>string</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imstscsecuredsettings-workdir" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#workdir-string-↗" aria-label="Permalink to “WorkDir (string) ↗”">​</a></h3><p>Specifies the working directory of the start program.</p><h2 id="events" tabindex="-1">Events <a class="header-anchor" href="#events" aria-label="Permalink to “Events”">​</a></h2><h3 id="onclientareaclicked" tabindex="-1"><code>OnClientAreaClicked</code> <a class="header-anchor" href="#onclientareaclicked" aria-label="Permalink to “OnClientAreaClicked”">​</a></h3><p>Handler Type: <code>EventHandler</code>?</p><p>Raised when the user clicks inside the remote desktop session and <a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-controls-clients-irdpclient">IRdpClient.DisableClickDetection</a> is disabled.</p><h2 id="methods" tabindex="-1">Methods <a class="header-anchor" href="#methods" aria-label="Permalink to “Methods”">​</a></h2><h3 id="geterrordescription-int32" tabindex="-1"><code>GetErrorDescription(Int32)</code> <a class="header-anchor" href="#geterrordescription-int32" aria-label="Permalink to “GetErrorDescription(Int32)”">​</a></h3><p>Returns: <code>string</code>. The error message text.</p><p>Retrieves the error description for the session disconnect events.</p><p><strong>Parameters</strong></p><ul><li><code>disconnectReasonCode</code> (<code>int</code>): The disconnect code.</li></ul><h3 id="raiseclientareaclicked" tabindex="-1"><code>RaiseClientAreaClicked()</code> <a class="header-anchor" href="#raiseclientareaclicked" aria-label="Permalink to “RaiseClientAreaClicked()”">​</a></h3><p>Returns: <code>void</code></p><p>Raises the OnClientAreaClicked event.</p><h3 id="updatesessiondisplaysettings-uint32-uint32-uint32-uint32-uint32-uint32-uint32-↗" tabindex="-1"><code>UpdateSessionDisplaySettings(UInt32, UInt32, UInt32, UInt32, UInt32, UInt32, UInt32)</code> <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/previous-versions/windows/desktop/legacy/mt703457(v=vs.85)" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#updatesessiondisplaysettings-uint32-uint32-uint32-uint32-uint32-uint32-uint32-↗" aria-label="Permalink to “UpdateSessionDisplaySettings(UInt32, UInt32, UInt32, UInt32, UInt32, UInt32, UInt32) ↗”">​</a></h3><p>Returns: <code>void</code></p><p>Updates the remote session display settings.</p><p><strong>Parameters</strong></p><ul><li><code>desktopWidth</code> (<code>uint</code>): Desktop width.</li><li><code>desktopHeight</code> (<code>uint</code>): Desktop height.</li><li><code>physicalWidth</code> (<code>uint</code>): Physical width.</li><li><code>physicalHeight</code> (<code>uint</code>): Physical height.</li><li><code>orientation</code> (<code>uint</code>): The display orientation.</li><li><code>desktopScaleFactor</code> (<code>uint</code>): Desktop scale factor.</li><li><code>deviceScaleFactor</code> (<code>uint</code>): Device scale factor.</li></ul><p><a href="./../">Back to API index</a></p>',176)])])}const b=r(i,[["render",n]]);export{m as __pageData,b as default};
